import type { ExamQuestion } from "./types";

export const npExamBatch73Questions: ExamQuestion[] = [
  { q: "A 62-year-old male with history of COPD presents with increased dyspnea, productive cough with purulent sputum, and wheezing. SpO2 is 88% on room air. What is the most appropriate initial management?", o: ["Start antibiotics and discharge home", "Administer nebulized albuterol/ipratropium, systemic corticosteroids, supplemental oxygen to target SpO2 88-92%, and antibiotics if purulent sputum", "Intubate immediately", "Order CT pulmonary angiogram"], a: 1, r: "GOLD guidelines for COPD exacerbation: bronchodilators (SABA + SAMA), systemic corticosteroids (prednisone 40 mg x 5 days), antibiotics if increased sputum purulence (amoxicillin-clavulanate, azithromycin, or respiratory fluoroquinolone), and controlled oxygen (target 88-92% to avoid CO2 retention in chronic hypercapnia). BiPAP if pH <7.35.", s: "Respiratory" },
  { q: "A 45-year-old woman presents with fatigue, joint pain, malar rash, and oral ulcers. ANA is positive at 1:640 with positive anti-dsDNA. What is the most likely diagnosis?", o: ["Rheumatoid arthritis", "Systemic lupus erythematosus", "Dermatomyositis", "Scleroderma"], a: 1, r: "SLE diagnostic criteria (ACR/EULAR 2019): ANA positivity is entry criterion. Weighted criteria include: malar rash, oral ulcers, arthritis, serositis, renal (proteinuria), neurologic, hematologic (cytopenias), anti-dsDNA, anti-Smith, low complement, direct Coombs. Anti-dsDNA is specific for SLE and correlates with disease activity, especially nephritis.", s: "Rheumatology" },
  { q: "A 30-year-old G1P0 at 34 weeks gestation presents with BP 168/108, proteinuria 3+, headache, and visual changes. What is the priority intervention?", o: ["Discharge with follow-up in 1 week", "Administer IV magnesium sulfate for seizure prophylaxis, antihypertensives, betamethasone for fetal lung maturity, and plan delivery", "Prescribe oral labetalol and recheck in 3 days", "Start induction of labor without medications"], a: 1, r: "Preeclampsia with severe features at 34 weeks: magnesium sulfate prevents eclamptic seizures (4-6g IV loading, then 1-2g/hr). Antihypertensives (IV labetalol, hydralazine, or oral nifedipine) target BP <160/110. Betamethasone 12 mg IM x 2 doses (24 hours apart) for fetal lung maturity if <34 weeks. Delivery indicated at >=34 weeks with severe features.", s: "Women's Health" },
  { q: "An 8-year-old presents with sore throat, fever, tonsillar exudates, and tender anterior cervical lymphadenopathy. Rapid strep test is positive. What is the treatment?", o: ["Amoxicillin 25 mg/kg/day for 5 days", "Amoxicillin 50 mg/kg/day (max 1000 mg) divided BID for 10 days or penicillin V for 10 days", "Azithromycin for 3 days", "Symptomatic treatment only"], a: 1, r: "GAS pharyngitis treatment: first-line amoxicillin 50 mg/kg/day (max 1000 mg) once daily or divided BID x 10 days, or penicillin V x 10 days. The 10-day course is essential to prevent acute rheumatic fever. PCN allergy: cephalexin (if no anaphylaxis history), azithromycin, or clindamycin. Centor/McIsaac criteria guide testing decisions.", s: "Pediatric" },
  { q: "A 70-year-old with atrial fibrillation on warfarin presents with INR of 8.5 and no active bleeding. What is the management?", o: ["Continue warfarin at same dose", "Hold warfarin, administer oral vitamin K 2.5-5 mg, recheck INR in 24 hours", "Administer IV vitamin K 10 mg and FFP", "Start heparin drip"], a: 1, r: "Supratherapeutic INR management without bleeding: INR 4.5-10 without significant bleeding: hold warfarin, consider low-dose oral vitamin K (2.5-5 mg). INR >10 without bleeding: hold warfarin, give oral vitamin K 2.5-5 mg. Major bleeding at any INR: IV vitamin K 10 mg + 4-factor PCC (preferred over FFP for faster reversal). Recheck INR in 24 hours and resume warfarin at reduced dose when INR therapeutic.", s: "Hematology" },
  { q: "A 55-year-old diabetic presents with a painless foot ulcer over the first metatarsal head. There is no erythema or drainage. ABI is 1.0. What is the classification and management?", o: ["Emergent surgical debridement", "Wagner grade 1 neuropathic ulcer; offload pressure with total contact cast or removable cast walker, wound care, optimize glycemic control, and monitor for infection", "Immediate amputation consultation", "Topical antibiotics only"], a: 1, r: "Diabetic foot ulcer Wagner classification: Grade 0 (at-risk foot), Grade 1 (superficial ulcer), Grade 2 (deep ulcer to tendon/joint), Grade 3 (deep with abscess/osteomyelitis), Grade 4 (partial gangrene), Grade 5 (complete gangrene). This is Grade 1 neuropathic ulcer with adequate perfusion (ABI 1.0). Management: offloading (TCC gold standard), moist wound healing, debridement of callus, glycemic control (A1c <7%), smoking cessation, and podiatry follow-up.", s: "Endocrine & Metabolic" },
  { q: "A 25-year-old presents with sudden onset palpitations, lightheadedness, and HR of 180 bpm. ECG shows narrow complex regular tachycardia with no discernible P waves. What is the first-line treatment?", o: ["Synchronized cardioversion", "Vagal maneuvers (modified Valsalva or carotid massage) followed by IV adenosine 6 mg rapid push if vagal maneuvers fail", "IV amiodarone", "Oral metoprolol"], a: 1, r: "SVT (supraventricular tachycardia): narrow complex, regular, rate 150-250. STABLE patient: vagal maneuvers first (modified Valsalva: blow into syringe in semi-recumbent position then lie flat and elevate legs — REVERT trial showed 43% success). If fails: adenosine 6 mg rapid IV push with NS flush (12 mg if first dose fails). Adenosine causes transient AV block, terminating re-entrant tachycardias. UNSTABLE: synchronized cardioversion.", s: "Cardiovascular" },
  { q: "A 3-month-old presents with projectile, non-bilious vomiting after every feeding for 2 weeks. Physical exam reveals a palpable olive-shaped mass in the epigastrium. What is the diagnosis?", o: ["GERD", "Pyloric stenosis requiring pyloromyotomy after correction of metabolic derangements (hypochloremic hypokalemic metabolic alkalosis)", "Malrotation with volvulus", "Intussusception"], a: 1, r: "Pyloric stenosis: hypertrophy of the pyloric muscle causing gastric outlet obstruction. Classic presentation: 2-8 week old infant with progressive, projectile, non-bilious vomiting; always hungry after vomiting; olive-shaped mass in RUQ/epigastrium; visible peristaltic waves. Labs: hypochloremic hypokalemic metabolic alkalosis (from HCl loss in vomitus). Diagnosis: ultrasound (pyloric muscle thickness >3mm, length >15mm). Treatment: fluid/electrolyte correction FIRST, then Ramstedt pyloromyotomy.", s: "Pediatric" },
  { q: "A 48-year-old presents with gradually worsening symmetric proximal muscle weakness (difficulty climbing stairs, rising from chair) for 3 months. CK is 4500 U/L. What is the most likely diagnosis?", o: ["Fibromyalgia", "Polymyositis or dermatomyositis; obtain anti-Jo-1 antibodies, MRI of affected muscles, and EMG; consider age-appropriate malignancy screening", "Hypothyroid myopathy", "Statin-induced myopathy"], a: 1, r: "Inflammatory myopathies: POLYMYOSITIS: symmetric proximal weakness, elevated CK, EMG shows myopathic changes, muscle biopsy shows endomysial inflammation. DERMATOMYOSITIS: same plus pathognomonic skin findings (heliotrope rash on eyelids, Gottron papules on knuckles, V-sign, shawl sign). Anti-Jo-1 antibodies: associated with antisynthetase syndrome (myositis, ILD, mechanic's hands, arthritis). Both associated with increased malignancy risk (especially DM) — age-appropriate cancer screening. Treatment: high-dose corticosteroids, steroid-sparing agents (methotrexate, azathioprine, IVIG).", s: "Rheumatology" },
  { q: "A 60-year-old with chronic liver disease presents with abdominal distension and shifting dullness. Diagnostic paracentesis shows SAAG 1.8 g/dL and total protein 1.5 g/dL. What is the diagnosis?", o: ["Malignant ascites", "Portal hypertensive ascites from cirrhosis; SAAG >=1.1 indicates portal hypertension; manage with sodium restriction and spironolactone", "Peritoneal carcinomatosis", "Tuberculous peritonitis"], a: 1, r: "Serum-ascites albumin gradient (SAAG): >=1.1 = portal hypertension (cirrhosis, HF, Budd-Chiari). <1.1 = non-portal hypertensive (malignancy, TB, nephrotic syndrome, pancreatitis). This patients SAAG 1.8 and low total protein (<2.5) is consistent with cirrhotic ascites. Management: sodium restriction (2g/day), diuretics (spironolactone 100 mg + furosemide 40 mg, maintain 100:40 ratio), therapeutic paracentesis if tense (give albumin 6-8g/L removed if >5L), TIPS for refractory ascites. SBP prophylaxis: if ascitic fluid protein <1.5.", s: "Gastrointestinal" },
  { q: "A 35-year-old IV drug user presents with fever, new heart murmur, and splinter hemorrhages. Blood cultures grow Staphylococcus aureus. What is the diagnosis?", o: ["Rheumatic heart disease", "Infective endocarditis; obtain echocardiography (TEE preferred for IV drug users with right-sided involvement) and initiate empiric IV antibiotics (vancomycin + gentamicin) pending sensitivities", "Viral myocarditis", "Mitral valve prolapse"], a: 1, r: "Infective endocarditis diagnosis: modified Duke criteria (2 major, 1 major + 3 minor, or 5 minor). MAJOR: positive blood cultures (typical organisms from >=2 cultures), echocardiographic evidence (vegetation, abscess, new dehiscence). MINOR: predisposition, fever, vascular phenomena (splinter hemorrhages, Janeway lesions, mycotic aneurysm), immunologic phenomena (Osler nodes, Roth spots, glomerulonephritis, RF). IVDU: typically right-sided (tricuspid) with S. aureus. Treatment: IV nafcillin/oxacillin (MSSA) or vancomycin (MRSA) for 4-6 weeks. Surgical consultation if heart failure, large vegetation, or embolic events.", s: "Cardiovascular" },
  { q: "A 28-year-old presents with episodic headaches preceded by visual aura (zigzag lines), followed by unilateral throbbing headache, nausea, and photophobia lasting 8 hours. What is the preventive treatment if attacks occur 6 times per month?", o: ["Only acute treatment needed", "Preventive therapy indicated: first-line options include propranolol, topiramate, amitriptyline, or valproic acid (avoid in women of childbearing age); CGRP monoclonal antibodies for refractory cases", "Daily triptan use", "Opioid prophylaxis"], a: 1, r: "Migraine prevention indicated if >=4 headache days/month, significant disability, or frequent/overuse of acute medications. FIRST-LINE: beta-blockers (propranolol 80-240 mg), antiepileptics (topiramate 100 mg — weight loss, cognitive effects, teratogenic), TCAs (amitriptyline 25-75 mg — sedation, weight gain), venlafaxine (SNRI). CGRP monoclonal antibodies (erenumab, fremanezumab, galcanezumab): for failure of >=2 traditional preventives. OnabotulinumtoxinA: FDA-approved for chronic migraine (>=15 days/month). Lifestyle: sleep hygiene, regular meals, exercise, stress management, trigger avoidance.", s: "Neurology" },
  { q: "A 65-year-old presents with a new finding of an abdominal aortic aneurysm measuring 4.8 cm on ultrasound screening. What is the management?", o: ["Immediate surgical repair", "Surveillance with repeat ultrasound every 6 months; surgical repair indicated when AAA reaches 5.5 cm or expands >0.5 cm in 6 months; optimize cardiovascular risk factors", "No follow-up needed", "CT angiogram now"], a: 1, r: "AAA management based on size: <4.0 cm: surveillance ultrasound every 2-3 years. 4.0-5.4 cm: surveillance every 6-12 months. >=5.5 cm (men) or >=5.0 cm (women): elective repair (open or EVAR). Rapid expansion (>0.5 cm in 6 months or >1 cm/year): repair regardless of size. RISK FACTOR management: smoking cessation (most important modifiable factor — accelerates expansion), statin, BP control (beta-blockers traditionally preferred but evidence limited), antiplatelet. SCREENING: USPSTF recommends one-time ultrasound for men 65-75 who have ever smoked.", s: "Cardiovascular" },
  { q: "A 40-year-old woman with SLE develops proteinuria (3.5 g/day), microscopic hematuria, and rising creatinine. Anti-dsDNA is elevated and complement levels are low. What is the most likely complication?", o: ["Drug-induced nephrotoxicity", "Lupus nephritis; renal biopsy is essential for classification (ISN/RPS class I-VI) to guide treatment with immunosuppressive therapy", "Diabetic nephropathy", "IgA nephropathy"], a: 1, r: "Lupus nephritis occurs in 50-60% of SLE patients. Signs: proteinuria, hematuria, rising creatinine, hypertension. Serologic activity: elevated anti-dsDNA, low C3/C4. RENAL BIOPSY is essential for ISN/RPS classification guiding treatment: Class I-II (minimal/mesangial): conservative. Class III (focal): immunosuppression. Class IV (diffuse — most common/severe): aggressive immunosuppression (mycophenolate or cyclophosphamide induction, then mycophenolate or azathioprine maintenance). Class V (membranous): immunosuppression if nephrotic. Class VI (sclerotic): consider transplant. Hydroxychloroquine for all SLE patients (reduces renal flares).", s: "Rheumatology" },
  { q: "A 50-year-old presents with progressive dysphagia to solids then liquids, weight loss of 15 lbs, and a feeling of food sticking in the chest. What is the most appropriate next step?", o: ["Barium swallow", "Upper endoscopy (EGD) with biopsy to evaluate for esophageal malignancy; progressive dysphagia from solids to liquids suggests mechanical obstruction", "Trial of PPI", "Chest X-ray"], a: 1, r: "Progressive dysphagia: SOLIDS ONLY suggests mechanical obstruction (stricture, Schatzki ring, tumor), SOLIDS AND LIQUIDS suggests motility disorder (achalasia, scleroderma). ALARM FEATURES: weight loss, progressive dysphagia, odynophagia, age >50 with new symptoms. This presentation (progressive solid to liquid, weight loss) requires URGENT EGD with biopsy to rule out esophageal carcinoma (squamous cell or adenocarcinoma). Risk factors: GERD/Barrett (adenocarcinoma), smoking/alcohol (squamous). Barium swallow is an alternative initial test but EGD allows tissue diagnosis.", s: "Gastrointestinal" },
  { q: "A 22-year-old college student presents with fever, pharyngitis, posterior cervical lymphadenopathy, and splenomegaly. CBC shows atypical lymphocytes. What is the diagnosis?", o: ["Strep pharyngitis", "Infectious mononucleosis caused by EBV; confirm with heterophile antibody test (Monospot) or EBV-specific antibodies; avoid contact sports for 3-4 weeks due to splenic rupture risk", "Acute HIV", "CMV infection"], a: 1, r: "Infectious mononucleosis (EBV): classic triad of pharyngitis, lymphadenopathy (especially posterior cervical), and fatigue. Splenomegaly in 50-60%. Atypical lymphocytes (activated T cells) on smear. Diagnosis: heterophile antibody test (Monospot, 85% sensitive after first week; false negatives in young children). EBV-specific antibodies (VCA IgM/IgG, EBNA) if Monospot negative. AVOID: amoxicillin/ampicillin (causes characteristic maculopapular rash in 70-100%), contact sports for 3-4 weeks (splenic rupture risk). Treatment: supportive (rest, fluids, analgesics). Consider acute HIV in differential (similar presentation).", s: "Infectious Disease" },
  { q: "A 75-year-old with osteoarthritis of the knee has failed NSAIDs, physical therapy, and intra-articular corticosteroid injections. What is the next step in management?", o: ["Continue current therapy", "Referral for total knee arthroplasty; also consider duloxetine for central pain modulation, topical capsaicin, intra-articular hyaluronic acid, and bracing", "Start opioid therapy", "MRI before any action"], a: 1, r: "OA knee stepped management: STEP 1: education, weight loss, exercise (quadriceps strengthening, aquatic therapy). STEP 2: topical NSAIDs (diclofenac gel), oral NSAIDs (shortest duration, gastroprotection if needed), acetaminophen. STEP 3: intra-articular corticosteroids (limit to 3-4/year per joint), duloxetine (central pain modulation, especially with comorbid depression). STEP 4: intra-articular hyaluronic acid (controversial evidence), bracing/orthotics. STEP 5: referral for total knee arthroplasty (excellent outcomes, 90%+ satisfaction, implant longevity 15-20+ years). Avoid opioids for chronic OA management.", s: "Musculoskeletal" },
  { q: "A 58-year-old with diabetes presents with burning pain and numbness in a stocking-glove distribution. Monofilament testing shows decreased sensation bilaterally. What is the diagnosis and treatment?", o: ["Lumbar radiculopathy", "Diabetic peripheral neuropathy; first-line treatment includes duloxetine, pregabalin, or gabapentin for neuropathic pain management plus optimized glycemic control and foot care", "Peripheral arterial disease", "Vitamin B12 deficiency"], a: 1, r: "Diabetic peripheral neuropathy: most common complication, length-dependent (stocking-glove distribution), symmetric, predominantly sensory (burning, tingling, numbness). Diagnosis: clinical (monofilament, vibration perception, ankle reflexes). RULE OUT other causes: B12 deficiency (metformin use), hypothyroidism, alcohol, CKD. PAIN MANAGEMENT: first-line duloxetine (SNRI, 60 mg daily) or pregabalin/gabapentin (calcium channel alpha-2-delta ligand). Second-line: TCAs (amitriptyline, but anticholinergic burden in elderly). Topical: capsaicin 8% patch, lidocaine patch. PREVENTION: glycemic control (A1c <7% reduces neuropathy risk by 60%), annual foot exams, patient education on foot care.", s: "Endocrine & Metabolic" },
  { q: "A 42-year-old presents with recurrent kidney stones. Analysis shows calcium oxalate composition. What metabolic evaluation and preventive measures are recommended?", o: ["No evaluation needed for first stone", "24-hour urine collection (calcium, oxalate, citrate, uric acid, sodium, volume), serum calcium, PTH if hypercalcemic; increase fluid intake to >2.5 L/day, dietary modifications, and consider thiazide diuretic", "Low-calcium diet", "High-dose vitamin C supplementation"], a: 1, r: "Recurrent calcium oxalate stones evaluation: 24-hour urine (calcium, oxalate, citrate, uric acid, sodium, creatinine, pH, volume). Serum: calcium, PTH (rule out hyperparathyroidism), uric acid, BMP. PREVENTION: fluid intake >2.5 L/day (urine output >2 L), dietary sodium restriction <2300 mg/day (reduces urinary calcium), NORMAL dietary calcium (1000-1200 mg/day — low calcium paradoxically increases oxalate absorption), reduce animal protein, increase fruits/vegetables (citrate). MEDICATIONS: thiazide diuretic (reduces urinary calcium), potassium citrate (increases citrate, alkalinizes urine). Do NOT restrict dietary calcium or supplement vitamin C (increases oxalate).", s: "Renal & Urologic" },
  { q: "A 35-year-old presents with a painless testicular mass. Ultrasound shows a solid intratesticular lesion. AFP is elevated, beta-hCG is normal. What is the most likely diagnosis and next step?", o: ["Epididymitis", "Testicular germ cell tumor (likely non-seminomatous due to elevated AFP); refer for radical inguinal orchiectomy; do NOT perform transscrotal biopsy", "Testicular torsion", "Hydrocele"], a: 1, r: "Painless testicular mass in a young male is testicular cancer until proven otherwise. TUMOR MARKERS: AFP elevated = non-seminomatous GCT (yolk sac tumor, embryonal, teratoma). Beta-hCG elevated = seminoma or choriocarcinoma. LDH = tumor burden. DIAGNOSIS: testicular ultrasound (solid intratesticular = cancer; extratesticular = likely benign). TREATMENT: radical inguinal orchiectomy (NEVER transscrotal approach — risk of tumor seeding). Staging CT chest/abdomen/pelvis. Seminoma: radiosensitive (radiation or surveillance for stage I). Non-seminoma: may require RPLND or chemotherapy (BEP: bleomycin, etoposide, cisplatin). Excellent prognosis: 95% cure rate.", s: "Renal & Urologic" },
  { q: "A 68-year-old presents with acute onset monocular vision loss described as a curtain coming down. Fundoscopic exam shows pale retina with cherry red spot. What is the diagnosis?", o: ["Retinal detachment", "Central retinal artery occlusion (CRAO); this is an ophthalmic emergency requiring immediate treatment within 90-120 minutes; evaluate for carotid/cardiac embolic source", "Optic neuritis", "Vitreous hemorrhage"], a: 1, r: "CRAO: sudden painless monocular vision loss from embolic occlusion of the central retinal artery. Fundoscopy: pale/edematous retina with cherry-red spot at macula (choroidal circulation visible through thin fovea). Afferent pupillary defect (Marcus Gunn pupil) present. EMERGENCY: retinal ischemia causes irreversible damage in 90-120 minutes. TREATMENT: ocular massage, anterior chamber paracentesis, carbogen inhalation, IV thrombolytics (emerging). WORKUP for embolic source: carotid duplex, echocardiography, ECG (AF), ESR/CRP (GCA in elderly — temporal artery biopsy if suspected). Differentiate from CRVO (dilated tortuous veins, widespread hemorrhages).", s: "Neurology" },
  { q: "A 45-year-old with HIV (CD4 count 180 cells/mm3) presents with white oral patches that do not scrape off. What is the most likely diagnosis?", o: ["Oral candidiasis", "Oral hairy leukoplakia caused by EBV; appears as white corrugated patches on lateral tongue borders that cannot be scraped off; indicates immunosuppression and need to optimize ART", "Lichen planus", "Leukoplakia requiring biopsy"], a: 1, r: "Oral hairy leukoplakia (OHL): EBV-associated white corrugated/hairy patches on LATERAL tongue borders. Does NOT scrape off (vs oral candidiasis which scrapes off revealing erythematous base). Painless. Occurs in immunosuppressed patients (HIV with CD4 <200, transplant recipients). NOT premalignant (vs true leukoplakia which may be). Treatment: usually self-resolves with ART and immune reconstitution. Acyclovir or valacyclovir if symptomatic. DIFFERENTIATE from: oral candidiasis (scrapes off), leukoplakia (requires biopsy to rule out dysplasia), lichen planus (Wickham striae).", s: "Infectious Disease" },
  { q: "A 55-year-old woman on long-term prednisone 20 mg daily for rheumatoid arthritis needs osteoporosis prevention. What is the appropriate intervention?", o: ["Calcium and vitamin D alone", "Start bisphosphonate therapy if glucocorticoid use expected >=3 months and prednisone >=2.5 mg/day; plus calcium 1200 mg and vitamin D 800-1000 IU daily; monitor with DEXA", "No intervention until fracture", "Only weight-bearing exercise"], a: 1, r: "Glucocorticoid-induced osteoporosis (GIOP): bone loss occurs rapidly (greatest in first 6-12 months). ACR 2022 guidelines: for adults on prednisone >=2.5 mg/day for >=3 months: risk stratification using FRAX (with glucocorticoid adjustment). MODERATE-HIGH RISK: oral bisphosphonate (alendronate, risedronate). HIGH RISK: IV zoledronic acid, teriparatide, or denosumab. ALL patients on glucocorticoids: calcium 1000-1200 mg/day + vitamin D 800-1000 IU/day, weight-bearing exercise, fall prevention. DEXA at baseline and annually. Use lowest effective glucocorticoid dose; consider steroid-sparing agents.", s: "Rheumatology" },
  { q: "A 4-year-old presents with periorbital edema, abdominal distension, and frothy urine. Urinalysis shows 4+ protein. Serum albumin is 1.8 g/dL. What is the most likely diagnosis?", o: ["Acute glomerulonephritis", "Nephrotic syndrome (most likely minimal change disease in children); characterized by massive proteinuria, hypoalbuminemia, edema, and hyperlipidemia; treat with oral corticosteroids", "UTI", "Henoch-Schonlein purpura"], a: 1, r: "Nephrotic syndrome in children: TRIAD: massive proteinuria (>3.5 g/day or urine protein/creatinine ratio >2), hypoalbuminemia (<2.5 g/dL), edema (periorbital first, then generalized/anasarca). Also: hyperlipidemia, lipiduria. Most common cause in children: MINIMAL CHANGE DISEASE (MCD, 80%). Treatment: oral prednisone 60 mg/m2/day for 4-6 weeks, then taper over 2-4 months. MCD has excellent steroid response (>90%). Complications: infections (spontaneous bacterial peritonitis, pneumococcal sepsis), thromboembolism (AT III loss), AKI. Biopsy if: steroid-resistant, atypical presentation, or age <1 or >12.", s: "Pediatric" },
  { q: "A 60-year-old smoker presents with hemoptysis, weight loss, and a centrally located lung mass on chest CT. What type of lung cancer is most likely?", o: ["Adenocarcinoma", "Squamous cell carcinoma (centrally located, associated with smoking and hypercalcemia from PTHrP); obtain tissue diagnosis with bronchoscopy and biopsy", "Small cell carcinoma", "Large cell carcinoma"], a: 1, r: "Lung cancer types by location: CENTRAL: squamous cell carcinoma (most common central tumor, cavitating, PTHrP causing hypercalcemia), small cell carcinoma (strongly associated with smoking, neuroendocrine, paraneoplastic syndromes — SIADH, Cushing, Lambert-Eaton). PERIPHERAL: adenocarcinoma (most common overall, can occur in non-smokers, associated with EGFR mutations). Diagnosis: bronchoscopy with biopsy for central lesions, CT-guided biopsy for peripheral. Staging: PET/CT, brain MRI. NSCLC staging determines surgery eligibility (stage I-IIIA potentially resectable). SCLC: limited vs extensive staging. Molecular testing for EGFR, ALK, ROS1, PD-L1 guides targeted therapy.", s: "Respiratory" },
  { q: "A 32-year-old woman presents with bilateral breast pain and multiple palpable lumpy areas that fluctuate with her menstrual cycle. What is the most likely diagnosis?", o: ["Breast cancer", "Fibrocystic breast changes; benign condition that does not increase cancer risk; manage with supportive bra, NSAIDs, and evening primrose oil; reassure patient", "Fibroadenoma", "Phyllodes tumor"], a: 1, r: "Fibrocystic breast changes: most common benign breast condition, affects 60-70% of women. Bilateral, diffuse nodularity and tenderness, fluctuating with menstrual cycle (worse premenstrually). NOT a risk factor for breast cancer. Management: supportive bra, NSAIDs, limit caffeine (limited evidence but commonly recommended), evening primrose oil, danazol for severe cases. Imaging: ultrasound for dominant cyst evaluation (simple cyst = benign, reassurance; complex cyst = biopsy). Aspiration for symptomatic cysts. Red flags warranting biopsy: bloody aspirate, cyst recurs after 2 aspirations, mass remains after aspiration.", s: "Women's Health" },
  { q: "A 78-year-old nursing home resident presents with sudden onset right-sided weakness and aphasia. Last known normal was 2 hours ago. CT head shows no hemorrhage. NIHSS is 18. What is the treatment?", o: ["Aspirin 325 mg immediately", "IV alteplase within 4.5-hour window (0.9 mg/kg, max 90 mg; 10% bolus, remainder over 60 min) PLUS evaluate for large vessel occlusion and possible mechanical thrombectomy", "Heparin drip", "Wait for MRI"], a: 1, r: "Acute ischemic stroke within treatment window: IV alteplase (tPA) if within 4.5 hours, BP <185/110 pre-treatment. NIHSS 18 suggests large vessel occlusion (LVO): evaluate with CTA head/neck for LVO amenable to mechanical thrombectomy (up to 24 hours with perfusion imaging selection per DAWN/DEFUSE-3 trials). Do NOT give aspirin for 24 hours after tPA. Post-tPA: admit to ICU/stroke unit, BP <180/105 for 24 hours, neuro checks every 15 minutes, CT head if any deterioration. Complications: hemorrhagic transformation (6% symptomatic).", s: "Neurology" },
  { q: "A 50-year-old presents with polyuria, polydipsia, and fatigue. Random glucose is 320 mg/dL. BMI is 42. A1c is 10.2%. What is the initial treatment approach?", o: ["Lifestyle modification alone", "Start metformin plus a GLP-1 receptor agonist (for glycemic control, weight loss, and cardiovascular benefit) or insulin if symptomatic/very high A1c; also lifestyle modifications", "Start insulin only", "Diet and recheck in 3 months"], a: 1, r: "New T2DM diagnosis with A1c >10%: ADA guidelines recommend initiating combination therapy or insulin. For this obese patient without DKA: METFORMIN (first-line) + GLP-1 RA (semaglutide preferred for weight loss benefit of 15-17% and cardiovascular risk reduction) is an excellent choice. If catabolic symptoms or very high glucose, insulin may be needed initially. SGLT2 inhibitor also considered (cardiovascular and renal benefits). Lifestyle: medical nutrition therapy, 150 min/week exercise, weight loss goal 5-10%. Follow-up A1c in 3 months to assess response and adjust therapy.", s: "Endocrine & Metabolic" },
  { q: "A 30-year-old presents with a 2 cm firm, rubbery, mobile, painless breast mass. Ultrasound shows a well-circumscribed solid lesion. What is the most likely diagnosis?", o: ["Breast cancer", "Fibroadenoma; most common benign solid breast tumor in young women; confirm with core needle biopsy or observe if classic features on imaging in patients under 35", "Phyllodes tumor", "Fat necrosis"], a: 1, r: "Fibroadenoma: most common benign solid breast mass in women 15-35 years. Characteristics: firm, rubbery, well-circumscribed, mobile (breast mouse), painless, usually 1-3 cm. Ultrasound: well-defined, homogeneous, wider-than-tall. Management: if classic features on imaging in patient <35: observation with follow-up ultrasound in 6 months is acceptable. Core needle biopsy for: atypical features, age >35, enlarging, patient preference. Giant fibroadenoma (>5 cm): excision recommended. Phyllodes tumor: larger, rapidly growing, leaf-like architecture, requires wide excision with margins. Fibroadenomas may involute after menopause.", s: "Women's Health" },
  { q: "A 6-year-old presents with cola-colored urine, periorbital edema, and hypertension 2 weeks after strep pharyngitis. What is the diagnosis?", o: ["UTI", "Post-streptococcal glomerulonephritis; diagnosis: elevated ASO titer, low C3 complement, and urinalysis with RBC casts and proteinuria; treatment is supportive", "Nephrotic syndrome", "IgA nephropathy"], a: 1, r: "Post-streptococcal glomerulonephritis (PSGN): immune complex-mediated GN occurring 1-3 weeks after pharyngitis or 3-6 weeks after skin infection with nephritogenic strains of GAS. NEPHRITIC SYNDROME: hematuria (cola/tea-colored), proteinuria (usually subnephrotic), hypertension, edema (periorbital), oliguria. Labs: elevated ASO/anti-DNase B, LOW C3 (returns to normal in 6-8 weeks), normal C4. UA: RBC casts (pathognomonic for GN), proteinuria, RBCs. Treatment: SUPPORTIVE (self-limited in children, 95% recovery): fluid/sodium restriction, loop diuretics for edema/hypertension, antihypertensives. Biopsy only if atypical course. C3 should normalize by 8 weeks; persistent low C3 suggests alternative diagnosis.", s: "Pediatric" },
  { q: "A 55-year-old with cirrhosis presents with fever, abdominal pain, and cloudy ascitic fluid. Ascitic fluid PMN count is 380 cells/mm3. What is the diagnosis and treatment?", o: ["Perforated viscus", "Spontaneous bacterial peritonitis (SBP); ascitic fluid PMN >=250 cells/mm3 is diagnostic; treat with IV ceftriaxone 2g daily and IV albumin 1.5 g/kg on day 1 and 1 g/kg on day 3", "Secondary peritonitis", "Tuberculous peritonitis"], a: 1, r: "SBP: infection of ascitic fluid without an intra-abdominal surgical source. Diagnosis: ascitic fluid PMN >=250 cells/mm3 (send cell count, culture — inoculate blood culture bottles at bedside, protein, glucose, LDH, amylase). TREATMENT: IV ceftriaxone 2g daily or cefotaxime 2g every 8 hours x 5-7 days. IV ALBUMIN: 1.5 g/kg on day 1 and 1 g/kg on day 3 (reduces mortality and renal failure, Sort trial). Secondary prophylaxis: lifelong norfloxacin or TMP-SMX. PRIMARY prophylaxis: if ascitic fluid protein <1.5 g/dL with renal dysfunction or liver failure. Rule out secondary bacterial peritonitis: total protein >1g/dL, glucose <50, LDH elevated, multiple organisms, polymicrobial.", s: "Gastrointestinal" },
  { q: "A 40-year-old presents with episodic hypertension (BP 220/130), headache, palpitations, and diaphoresis. What endocrine tumor should be suspected?", o: ["Cushing syndrome", "Pheochromocytoma; screen with plasma free metanephrines or 24-hour urine metanephrines and catecholamines; CT/MRI adrenals for localization; alpha-blockade before surgery", "Primary aldosteronism", "Thyroid storm"], a: 1, r: "Pheochromocytoma: catecholamine-secreting tumor of adrenal medulla (90%) or extra-adrenal paraganglia (10%). Classic triad: episodic hypertension, headache, diaphoresis + palpitations, pallor, anxiety. Rule of 10s (somewhat outdated): 10% bilateral, 10% extra-adrenal, 10% malignant, 10% familial. SCREENING: plasma free metanephrines (most sensitive, >99%) or 24-hour urine metanephrines/catecholamines. LOCALIZATION: CT or MRI abdomen (MRI preferred for pregnancy, radiation avoidance). TREATMENT: ALPHA-BLOCKADE FIRST (phenoxybenzamine or doxazosin) for 10-14 days before surgery, then add beta-blocker. Never beta-block first (unopposed alpha stimulation = hypertensive crisis). Surgical adrenalectomy is curative.", s: "Endocrine & Metabolic" },
  { q: "A 72-year-old presents with bone pain, anemia, hypercalcemia, and renal insufficiency. Serum protein electrophoresis shows an M-spike. What is the diagnosis?", o: ["Metastatic bone disease", "Multiple myeloma; further workup includes SPEP/UPEP, serum free light chains, bone marrow biopsy, and skeletal survey or PET/CT. CRAB criteria: Calcium elevated, Renal insufficiency, Anemia, Bone lesions", "Osteoporosis", "Hyperparathyroidism"], a: 1, r: "Multiple myeloma: malignant plasma cell neoplasm. CRAB criteria (end-organ damage): Calcium elevated (>11 mg/dL), Renal insufficiency (Cr >2), Anemia (Hgb <10), Bone lesions (lytic lesions, pathologic fractures, osteoporosis). DIAGNOSIS: serum/urine protein electrophoresis (M-spike), serum free light chains (kappa/lambda ratio), bone marrow biopsy (>=10% clonal plasma cells), skeletal survey or PET-CT (lytic lesions, no blastic lesions — avoid radionuclide bone scan as MM lesions dont take up tracer). TREATMENT: proteasome inhibitors (bortezomib), immunomodulators (lenalidomide), dexamethasone, anti-CD38 antibodies (daratumumab), autologous stem cell transplant in eligible patients. Supportive: bisphosphonates (zoledronic acid), erythropoietin for anemia.", s: "Hematology" },
  { q: "A 25-year-old presents with bloody diarrhea, abdominal cramping, and tenesmus for 3 weeks. Colonoscopy shows continuous inflammation from the rectum extending proximally with loss of haustra. What is the diagnosis?", o: ["Crohn disease", "Ulcerative colitis; continuous mucosal inflammation starting at rectum; treat with 5-ASA for mild-moderate, corticosteroids for flares, and immunomodulators or biologics for moderate-severe", "Infectious colitis", "Ischemic colitis"], a: 1, r: "Ulcerative colitis vs Crohn disease: UC: continuous inflammation starting at RECTUM extending proximally (never skip lesions), mucosal/submucosal only, bloody diarrhea, lead pipe colon (loss of haustra), crypt abscesses, increased colorectal cancer risk. CROHN: any GI location (mouth to anus), skip lesions, transmural inflammation (fistulas, abscesses, strictures), cobblestone mucosa, non-caseating granulomas, perianal disease. UC TREATMENT: 5-ASA (mesalamine) for mild-moderate; corticosteroids for flares (not maintenance); immunomodulators (azathioprine, 6-MP); biologics (infliximab, adalimumab, vedolizumab, tofacitinib); colectomy for refractory disease or dysplasia.", s: "Gastrointestinal" },
  { q: "A 38-year-old presents with a neck mass, weight loss, night sweats, and pruritus. Biopsy shows Reed-Sternberg cells. What is the diagnosis?", o: ["Non-Hodgkin lymphoma", "Hodgkin lymphoma; characterized by Reed-Sternberg cells; staging with PET/CT; B symptoms (fever, night sweats, >10% weight loss) indicate more advanced disease", "Thyroid cancer", "Reactive lymphadenopathy"], a: 1, r: "Hodgkin lymphoma: bimodal age distribution (15-35 and >55). PATHOGNOMONIC: Reed-Sternberg cells (large binucleated cells, owl-eye appearance). Types: nodular sclerosis (most common), mixed cellularity, lymphocyte-rich, lymphocyte-depleted. B SYMPTOMS (prognostic): fever >38C, drenching night sweats, unintentional weight loss >10% in 6 months. STAGING: PET/CT (most sensitive). Ann Arbor staging: I (single node region), II (>=2 regions same side of diaphragm), III (both sides), IV (extranodal dissemination). TREATMENT: ABVD (doxorubicin, bleomycin, vinblastine, dacarbazine) for early stage; escalated BEACOPP or ABVD + radiation for advanced. Excellent prognosis: >80% cure rate overall.", s: "Hematology" },
  { q: "A 65-year-old with chronic back pain and insomnia asks for a prescription for alprazolam. What is the appropriate response?", o: ["Prescribe alprazolam as requested", "Explain that benzodiazepines are high-risk in elderly (Beers Criteria); offer evidence-based alternatives: CBT-I for insomnia, duloxetine or gabapentin for chronic pain, and non-benzodiazepine options for anxiety if present", "Prescribe zolpidem instead", "Refer to pain clinic without addressing insomnia"], a: 1, r: "Benzodiazepines in elderly (AGS Beers Criteria): increased risk of falls (OR 1.5), fractures, cognitive impairment, motor vehicle accidents, and paradoxical agitation. INSOMNIA alternatives: CBT-I (first-line, sustained benefit), sleep hygiene, melatonin, low-dose trazodone, suvorexant (orexin receptor antagonist). CHRONIC PAIN: duloxetine (comorbid depression/pain), gabapentin/pregabalin (neuropathic pain), topical agents, PT, CBT for pain. ANXIETY: SSRIs/SNRIs, buspirone, hydroxyzine. Apply shared decision-making: acknowledge the request respectfully, explain risks, offer effective alternatives, and develop a comprehensive treatment plan.", s: "Geriatric" },
{ q: "A 52-year-old woman with BMI 38, type 2 diabetes, and hypertension asks about weight loss medication. Which agent provides the greatest weight loss AND cardiovascular benefit?", o: ["Orlistat 120 mg TID", "Semaglutide 2.4 mg SC weekly (Wegovy)", "Phentermine 37.5 mg daily", "Naltrexone-bupropion ER (Contrave)"], a: 1, r: "Semaglutide 2.4 mg (Wegovy) demonstrated 15-17% weight loss in STEP trials and 20% MACE reduction in the SELECT trial. Orlistat provides only 3-4% weight loss. Phentermine is short-term only. Naltrexone-bupropion provides 5-6% without proven CV benefit.", s: "Endocrine" },
  { q: "Which medication for obesity management is Category X in pregnancy due to risk of cleft palate?", o: ["Semaglutide", "Orlistat", "Phentermine-topiramate ER (Qsymia)", "Liraglutide"], a: 2, r: "Phentermine-topiramate ER (Qsymia) is Category X due to topiramate's teratogenic effect causing cleft palate/lip. The REMS program requires monthly pregnancy testing. Women of childbearing potential must use effective contraception.", s: "Pharmacology" },
  { q: "An NP is evaluating a patient on semaglutide 2.4 mg weekly for 16 weeks who has lost only 2.8% body weight. The patient is adherent. What is the appropriate next step?", o: ["Continue for another 12 weeks", "Add orlistat to the regimen", "Discontinue semaglutide as the patient is a non-responder and consider alternative therapy", "Increase to 3.6 mg weekly"], a: 2, r: "Guidelines recommend discontinuing anti-obesity medications if <5% weight loss is not achieved after 12-16 weeks at maximum tolerated dose. The patient is a non-responder. Consider tirzepatide, naltrexone-bupropion, or bariatric surgery referral.", s: "Endocrine" },
  { q: "Which anthropometric measurement is a better predictor of cardiovascular risk than BMI?", o: ["Hip circumference", "Waist circumference", "Neck circumference", "Thigh circumference"], a: 1, r: "Waist circumference reflects visceral adiposity, which is more metabolically active than subcutaneous fat. Central obesity (>40 inches males, >35 inches females) is a better predictor of cardiometabolic risk than BMI. A normal-BMI patient with central obesity has elevated risk.", s: "Endocrine" },
  { q: "What is the primary mechanism by which leptin resistance contributes to obesity?", o: ["Increased insulin secretion", "SOCS3-mediated suppression of hypothalamic leptin signaling impairing satiety", "Enhanced lipolysis in adipose tissue", "Decreased ghrelin secretion"], a: 1, r: "In obesity, chronic hyperleptinemia leads to upregulation of SOCS3 (suppressor of cytokine signaling 3), which inhibits JAK-STAT3 signaling downstream of the leptin receptor, rendering the hypothalamus resistant to leptin's satiety signal despite elevated levels.", s: "Endocrine" },
  { q: "The 2022 ASMBS/IFSO guidelines lowered the bariatric surgery threshold to which BMI with metabolic disease?", o: ["BMI ≥40", "BMI ≥35", "BMI ≥30", "BMI ≥25"], a: 2, r: "Updated 2022 ASMBS/IFSO guidelines recommend bariatric surgery for BMI ≥35 regardless of comorbidities, or BMI 30-34.9 with metabolic disease. This represents a significant change from prior guidelines that required BMI ≥40 or ≥35 with comorbidities.", s: "Endocrine" },
  { q: "Tirzepatide (Zepbound) acts as a dual agonist at which two receptors?", o: ["GLP-1 and glucagon receptors", "GIP and GLP-1 receptors", "Leptin and insulin receptors", "D1 and D2 dopamine receptors"], a: 1, r: "Tirzepatide is a dual GIP (glucose-dependent insulinotropic polypeptide) and GLP-1 (glucagon-like peptide-1) receptor agonist. In the SURMOUNT trials, it achieved 20-22% weight loss, the highest among currently approved anti-obesity medications.", s: "Pharmacology" },
  { q: "A patient with BMI 32 and metabolic syndrome asks about orlistat. Which counseling point is most important?", o: ["Take on an empty stomach", "GI side effects (oily stool, flatulence, fecal urgency) worsen with high-fat meals", "It is the most effective oral weight loss medication", "It increases serotonin levels"], a: 1, r: "Orlistat inhibits pancreatic and gastric lipase, preventing ~30% of dietary fat absorption. GI side effects (steatorrhea, oily spotting, fecal urgency) are worsened by high-fat meals. Patients should eat ≤30% calories from fat. Supplement fat-soluble vitamins (A, D, E, K).", s: "Pharmacology" },
  { q: "After significant weight loss, which hormonal changes promote weight regain?", o: ["Increased leptin and decreased ghrelin", "Decreased ghrelin and increased PYY", "Increased ghrelin, decreased leptin, decreased PYY, and decreased GLP-1", "Increased adiponectin and decreased cortisol"], a: 2, r: "Metabolic adaptation after weight loss includes increased ghrelin (hunger hormone) and decreased leptin, PYY, and GLP-1 (satiety signals), creating a hormonal milieu that promotes increased food intake and weight regain. This adaptation persists for years.", s: "Endocrine" },
  { q: "Which screening tool is recommended for obstructive sleep apnea in obese patients?", o: ["PHQ-9", "STOP-BANG questionnaire", "Fagerström test", "AUDIT-C"], a: 1, r: "The STOP-BANG questionnaire screens for OSA risk factors: Snoring, Tiredness, Observed apnea, Pressure (hypertension), BMI >35, Age >50, Neck circumference >40 cm, Gender (male). A score ≥3 indicates moderate risk; polysomnography confirms diagnosis.", s: "Assessment" },
  { q: "What defines metabolic syndrome? The patient must have at least how many of the five criteria?", o: ["2 of 5", "3 of 5", "4 of 5", "All 5"], a: 1, r: "Metabolic syndrome requires ≥3 of 5 criteria: elevated waist circumference (>40\" males, >35\" females), triglycerides ≥150, HDL <40 males/<50 females, BP ≥130/85, fasting glucose ≥100 mg/dL. It increases cardiovascular and diabetes risk significantly.", s: "Assessment" },
  { q: "A patient on naltrexone-bupropion (Contrave) for obesity asks about alcohol use. What is the most important counseling point?", o: ["Alcohol is safe in moderation", "Naltrexone blocks opioid receptors and may reduce the rewarding effects of alcohol; bupropion lowers seizure threshold, and alcohol withdrawal increases seizure risk", "The medication increases alcohol tolerance", "Switch to orlistat if they drink alcohol"], a: 1, r: "Naltrexone is an opioid receptor antagonist that also reduces alcohol's rewarding effects. Bupropion lowers seizure threshold, and alcohol use (especially abrupt cessation) further increases seizure risk. Patients should avoid heavy alcohol use and not abruptly discontinue alcohol.", s: "Pharmacology" },
  { q: "Which lab finding in an obese patient suggests non-alcoholic fatty liver disease (NAFLD)?", o: ["Elevated TSH", "Elevated ALT/AST with AST:ALT ratio <1", "Decreased albumin", "Elevated direct bilirubin"], a: 1, r: "NAFLD is characterized by elevated ALT (often higher than AST, so AST:ALT ratio <1, distinguishing it from alcoholic hepatitis where ratio is >2). Hepatic transaminase screening is recommended in obese patients. NAFLD can progress to NASH, cirrhosis, and hepatocellular carcinoma.", s: "Endocrine" },
  { q: "What is the mechanism of action of semaglutide that contributes to weight loss?", o: ["Lipase inhibition preventing fat absorption", "Norepinephrine release in the hypothalamus", "GLP-1 receptor activation in hypothalamic satiety centers reducing appetite and slowing gastric emptying", "GABA enhancement reducing food reward"], a: 2, r: "Semaglutide mimics GLP-1, activating receptors in the hypothalamic arcuate nucleus to reduce appetite, in the brainstem to slow gastric emptying (promoting early satiety), and in the mesolimbic system to reduce food reward. It also enhances glucose-dependent insulin secretion.", s: "Pharmacology" },
  { q: "A morbidly obese patient (BMI 44) with severe OSA and type 2 diabetes has failed pharmacotherapy. What intervention has the highest probability of sustained weight loss and diabetes remission?", o: ["Intensive behavioral modification alone", "Higher dose semaglutide", "Bariatric surgery (Roux-en-Y gastric bypass or sleeve gastrectomy)", "Very low calorie diet (800 kcal/day) for 12 weeks"], a: 2, r: "Bariatric surgery achieves 25-35% sustained weight loss and type 2 diabetes remission rates of 30-63% at 5 years (STAMPEDE trial). For BMI ≥40 with comorbidities, surgery is indicated when pharmacotherapy has failed. Roux-en-Y provides the highest diabetes remission rates.", s: "Endocrine" },
  { q: "Which medication class used for other indications commonly causes weight gain and should be avoided in obese patients when alternatives exist?", o: ["ACE inhibitors", "SSRIs", "Atypical antipsychotics (olanzapine, clozapine)", "Thiazide diuretics"], a: 2, r: "Atypical antipsychotics, particularly olanzapine and clozapine, cause significant weight gain (5-10+ kg) through histamine H1 and serotonin 5-HT2C receptor antagonism. Other weight-gaining medications include glucocorticoids, insulin, sulfonylureas, TCAs, and valproic acid.", s: "Pharmacology" },
  { q: "An obese patient has fasting glucose 112 mg/dL and HbA1c 6.1%. How is this classified?", o: ["Normal", "Prediabetes", "Type 2 diabetes mellitus", "Impaired fasting glucose only"], a: 1, r: "Prediabetes criteria: fasting glucose 100-125 mg/dL (impaired fasting glucose), HbA1c 5.7-6.4%, or 2-hour OGTT 140-199. This patient meets criteria for both impaired fasting glucose and prediabetes HbA1c range. Lifestyle intervention reduces progression to T2DM by 58% (DPP trial).", s: "Endocrine" },
  { q: "What is the boxed warning for semaglutide (Wegovy)?", o: ["Hepatotoxicity", "Risk of thyroid C-cell tumors (medullary thyroid carcinoma) based on rodent studies", "QT prolongation", "Stevens-Johnson syndrome"], a: 1, r: "All GLP-1 receptor agonists carry a boxed warning for thyroid C-cell tumor risk based on rodent studies (dose-dependent thyroid C-cell adenomas and carcinomas in rats). Contraindicated in patients with personal or family history of medullary thyroid carcinoma or MEN type 2.", s: "Pharmacology" },
  { q: "An obese patient with PCOS asks about weight loss. Which statement about weight loss and PCOS is most accurate?", o: ["Weight loss does not affect PCOS symptoms", "Even 5-10% weight loss can restore ovulatory cycles, improve insulin resistance, and reduce hyperandrogenism in PCOS", "Weight loss worsens hirsutism", "Only surgical weight loss benefits PCOS"], a: 1, r: "In PCOS, excess adipose tissue contributes to insulin resistance and hyperandrogenism through peripheral aromatization. Even modest weight loss (5-10%) can restore ovulatory cycles, improve insulin sensitivity, reduce testosterone levels, and improve hirsutism.", s: "Endocrine" },
  { q: "Which component of the HOMA-IR calculation indicates insulin resistance?", o: ["Fasting glucose only", "Fasting insulin only", "Fasting glucose × fasting insulin / 405 — values >2.5 suggest insulin resistance", "Postprandial glucose / baseline glucose"], a: 2, r: "HOMA-IR (Homeostatic Model Assessment of Insulin Resistance) is calculated as fasting glucose (mg/dL) × fasting insulin (μU/mL) / 405. Values >2.5 suggest insulin resistance. It helps identify metabolically unhealthy obesity and guides treatment decisions.", s: "Endocrine" },
  { q: "A patient on phentermine-topiramate ER reports tingling in hands and feet. What is the likely cause?", o: ["Peripheral vascular disease", "Topiramate-induced paresthesias from carbonic anhydrase inhibition", "Phentermine-induced vasoconstriction", "Diabetic neuropathy"], a: 1, r: "Paresthesias (tingling, numbness) are a common side effect of topiramate caused by carbonic anhydrase inhibition affecting peripheral nerve function. This typically occurs in hands and feet, is dose-dependent, and often resolves with dose adjustment.", s: "Pharmacology" },
  { q: "What is the primary role of adiponectin in metabolic health?", o: ["Promotes insulin resistance", "Enhances insulin sensitivity via AMPK activation and promotes fatty acid oxidation", "Increases appetite via hypothalamic signaling", "Stimulates lipogenesis in hepatocytes"], a: 1, r: "Adiponectin enhances insulin sensitivity by activating AMP-activated protein kinase (AMPK) in skeletal muscle and liver, increasing glucose uptake and fatty acid oxidation. Adiponectin levels are paradoxically DECREASED in obesity despite more adipose tissue, contributing to insulin resistance.", s: "Endocrine" },
  { q: "Which imaging modality confirms NAFLD in an obese patient with elevated transaminases?", o: ["Abdominal X-ray", "Liver ultrasound showing hepatic steatosis", "CT chest", "MRCP"], a: 1, r: "Liver ultrasound demonstrating hepatic steatosis (increased echogenicity) is the first-line imaging for NAFLD. FibroScan (transient elastography) assesses fibrosis severity. Liver biopsy remains the gold standard for distinguishing simple steatosis from NASH.", s: "Assessment" },
  { q: "A patient with BMI 42 undergoes Roux-en-Y gastric bypass. Which nutritional deficiencies require lifelong monitoring?", o: ["Only vitamin D", "Iron, vitamin B12, folate, calcium, vitamin D, and fat-soluble vitamins (A, E, K)", "Only protein", "No supplementation needed after surgery"], a: 1, r: "Roux-en-Y gastric bypass bypasses the duodenum and proximal jejunum where iron, calcium, and fat-soluble vitamins are absorbed. B12 absorption is impaired due to reduced intrinsic factor from the bypassed fundus. Lifelong supplementation and monitoring are mandatory.", s: "Endocrine" },
  { q: "What distinguishes visceral adipose tissue from subcutaneous adipose tissue in metabolic risk?", o: ["Subcutaneous fat is more metabolically active", "Visceral fat drains into the portal circulation exposing the liver to free fatty acids and inflammatory cytokines", "They have identical metabolic profiles", "Subcutaneous fat produces more IL-6"], a: 1, r: "Visceral (intra-abdominal) adipose tissue is more metabolically active, secreting higher levels of pro-inflammatory cytokines (IL-6, TNF-alpha) and free fatty acids. It drains via the portal vein directly to the liver, promoting hepatic insulin resistance, NAFLD, and atherogenic dyslipidemia.", s: "Endocrine" },
  { q: "An obese patient asks about intermittent fasting for weight loss. Which evidence-based counseling is most accurate?", o: ["Intermittent fasting is the only effective dietary strategy", "Intermittent fasting produces similar weight loss to continuous caloric restriction; the best diet is one the patient can adhere to long-term", "Intermittent fasting is contraindicated in all patients", "Intermittent fasting doubles metabolic rate"], a: 1, r: "Meta-analyses show intermittent fasting produces comparable weight loss to continuous caloric restriction (3-8% over 3-12 months). No single dietary pattern is superior; adherence is the strongest predictor of success. The NP should recommend the approach most compatible with the patient's lifestyle.", s: "Endocrine" },
  { q: "Which GLP-1 receptor agonist for weight loss is administered as a daily subcutaneous injection?", o: ["Semaglutide 2.4 mg (Wegovy)", "Tirzepatide (Zepbound)", "Liraglutide 3.0 mg (Saxenda)", "Dulaglutide (Trulicity)"], a: 2, r: "Liraglutide 3.0 mg (Saxenda) is the daily injectable GLP-1 RA for obesity. Semaglutide (Wegovy) and tirzepatide (Zepbound) are weekly injections. Liraglutide achieves 5-8% weight loss. Its shorter half-life (13 hours vs 7 days for semaglutide) necessitates daily dosing.", s: "Pharmacology" },
  { q: "What is the recommended approach when an obese patient has both hypertension and needs weight loss medication?", o: ["Avoid all weight loss medications", "Consider semaglutide or tirzepatide which provide weight loss AND cardiovascular/blood pressure benefit; avoid phentermine in uncontrolled hypertension", "Start phentermine first for rapid weight loss", "Weight loss medications worsen hypertension universally"], a: 1, r: "GLP-1 RAs (semaglutide, tirzepatide) reduce blood pressure by 2-5 mmHg in addition to weight loss. Phentermine is a sympathomimetic that can increase BP and heart rate and is contraindicated in uncontrolled hypertension. Medication selection should consider comorbidities.", s: "Pharmacology" },
  { q: "What percentage of dopaminergic neurons in the substantia nigra must be lost before motor symptoms of Parkinson disease appear clinically?", o: ["10-20%", "30-40%", "60-80%", "95-100%"], a: 2, r: "Approximately 60-80% of dopaminergic neurons in the substantia nigra pars compacta are lost before motor symptoms manifest, indicating a prolonged preclinical phase. This explains why prodromal non-motor symptoms (hyposmia, REM sleep behavior disorder, constipation) precede motor features by years.", s: "Neurological" },
  { q: "A patient with early Parkinson disease notices food affecting their carbidopa-levodopa response. Which dietary counseling is most important?", o: ["Increase protein intake with each dose", "Avoid high-protein meals around dosing times as amino acids compete with levodopa for intestinal absorption and BBB transport", "Take with a glass of milk for better absorption", "Protein has no effect on levodopa absorption"], a: 1, r: "Large neutral amino acids from dietary protein compete with levodopa for absorption via the LAT1 transporter in both the intestine and blood-brain barrier. High-protein meals significantly reduce levodopa bioavailability. Patients should take levodopa 30-60 minutes before meals or redistribute protein to the evening.", s: "Pharmacology" },
  { q: "Which non-motor symptom of Parkinson disease often precedes motor symptoms by years and is a strong prodromal marker?", o: ["Hearing loss", "REM sleep behavior disorder", "Peripheral neuropathy", "Visual field deficits"], a: 1, r: "REM sleep behavior disorder (loss of normal REM atonia, resulting in acting out dreams) precedes PD motor symptoms by 5-15+ years. It reflects alpha-synuclein pathology in the brainstem (Braak stages 1-2) before it reaches the substantia nigra. Over 80% of RBD patients eventually develop PD or a related synucleinopathy.", s: "Neurological" },
  { q: "A 60-year-old patient on pramipexole for PD reports sudden uncontrollable shopping sprees and gambling. What is this side effect called?", o: ["Psychosis", "Impulse control disorder", "Mania", "Obsessive-compulsive disorder"], a: 1, r: "Impulse control disorders (pathological gambling, compulsive shopping, hypersexuality, binge eating) affect 15-20% of patients on dopamine agonists, mediated by D3 receptor stimulation in the mesolimbic reward pathway. Management: taper the dopamine agonist and substitute levodopa.", s: "Pharmacology" },
  { q: "What imaging study can differentiate Parkinson disease from essential tremor when the clinical diagnosis is uncertain?", o: ["MRI brain", "CT head", "DaTscan (dopamine transporter SPECT imaging)", "EEG"], a: 2, r: "DaTscan uses 123I-ioflupane to image dopamine transporters in the striatum. Reduced uptake indicates dopaminergic neuron loss (PD, MSA, DLB), while essential tremor shows normal uptake. MRI is typically normal in PD and is used primarily to exclude structural lesions.", s: "Neurological" },
  { q: "A PD patient on carbidopa-levodopa for 8 years develops involuntary choreiform movements at peak medication levels. This is called:", o: ["Wearing-off phenomenon", "On-off fluctuations", "Peak-dose dyskinesias", "Akathisia"], a: 2, r: "Peak-dose dyskinesias are involuntary choreiform movements occurring at peak levodopa plasma levels. They develop in 40-50% of patients after 5-10 years of levodopa therapy due to progressive dopaminergic neuron loss and pulsatile receptor stimulation. Management: reduce individual levodopa dose (increase frequency), add amantadine.", s: "Neurological" },
  { q: "Which antipsychotic can be safely used in a Parkinson disease patient with psychosis?", o: ["Haloperidol", "Risperidone", "Quetiapine", "Chlorpromazine"], a: 2, r: "Quetiapine has the lowest D2 receptor affinity among antipsychotics and is the safest option for PD psychosis. Clozapine is also safe but requires monitoring for agranulocytosis. Typical antipsychotics (haloperidol) and high-D2-affinity atypicals (risperidone) worsen parkinsonism. Pimavanserin (Nuplazid) is FDA-approved specifically for PD psychosis.", s: "Pharmacology" },
  { q: "Which medication is used to treat levodopa-induced dyskinesias?", o: ["Benztropine", "Amantadine", "Trihexyphenidyl", "Bromocriptine"], a: 1, r: "Amantadine, an NMDA glutamate receptor antagonist, is the only FDA-approved medication for levodopa-induced dyskinesias (extended-release form, Gocovri). It reduces glutamatergic overactivity in the basal ganglia. Anticholinergics (benztropine, trihexyphenidyl) treat tremor but not dyskinesias.", s: "Pharmacology" },
  { q: "The Braak staging hypothesis for Parkinson disease proposes alpha-synuclein pathology begins in which structures?", o: ["Substantia nigra and striatum", "Olfactory bulb and dorsal motor nucleus of the vagus", "Cerebral cortex", "Cerebellum"], a: 1, r: "Braak staging proposes alpha-synuclein pathology begins in the olfactory bulb and dorsal motor nucleus of the vagus (stages 1-2), explaining early hyposmia and constipation. Pathology then ascends to the midbrain (stages 3-4, motor symptoms) and neocortex (stages 5-6, dementia).", s: "Neurological" },
  { q: "A patient with suspected bacterial meningitis has altered mental status. What must be done BEFORE lumbar puncture?", o: ["Nothing, proceed directly to LP", "CT head to rule out mass lesion or elevated ICP, BUT start empiric antibiotics before CT results", "Wait for infectious disease consultation", "Obtain only blood cultures and defer LP"], a: 1, r: "CT before LP is required when altered mental status, focal neurological deficits, papilledema, seizures, or immunocompromised state are present (herniation risk). However, antibiotics (vancomycin + ceftriaxone ± ampicillin) must be started IMMEDIATELY before CT — never delay antibiotics for imaging.", s: "Neurological" },
  { q: "CSF analysis shows WBC 2500 (90% neutrophils), protein 250 mg/dL, glucose 22 mg/dL (serum 110). This pattern is consistent with:", o: ["Viral meningitis", "Bacterial meningitis", "Fungal meningitis", "Normal CSF"], a: 1, r: "Bacterial meningitis CSF profile: elevated WBC with neutrophil predominance (>80%), markedly elevated protein (>100 mg/dL), and low glucose (<40 mg/dL or CSF:serum ratio <0.4). Viral meningitis shows lymphocytic pleocytosis with normal glucose. Fungal meningitis shows lymphocytic pleocytosis with low glucose.", s: "Neurological" },
  { q: "When must dexamethasone be given in suspected pneumococcal meningitis to reduce mortality?", o: ["After CSF culture results are finalized", "BEFORE or WITH the first dose of antibiotics", "24 hours after antibiotics are started", "Only if the patient does not improve in 48 hours"], a: 1, r: "Dexamethasone must be administered BEFORE or simultaneously WITH the first antibiotic dose to reduce the inflammatory cascade before bacterial lysis releases more cell wall fragments. If antibiotics were started >1 hour ago, dexamethasone benefit is lost (de Gans trial, 2002).", s: "Pharmacology" },
  { q: "A college student is diagnosed with Neisseria meningitidis meningitis. Which chemoprophylaxis should the NP prescribe for close contacts?", o: ["Amoxicillin 500 mg PO BID x5 days", "Ciprofloxacin 500 mg PO single dose", "Azithromycin 1 g PO single dose", "Doxycycline 100 mg PO BID x7 days"], a: 1, r: "Chemoprophylaxis for meningococcal close contacts: ciprofloxacin 500 mg PO x1 dose (preferred in adults), rifampin 600 mg PO q12h x2 days, or ceftriaxone 250 mg IM x1 dose (preferred in pregnancy). Must be given within 24 hours of case identification to all close contacts.", s: "Pharmacology" },
  { q: "What is the classic meningococcal rash?", o: ["Maculopapular rash on trunk only", "Petechial or purpuric rash that does not blanch", "Vesicular rash in a dermatomal pattern", "Erythema migrans with central clearing"], a: 1, r: "Meningococcemia produces a characteristic petechial/purpuric rash from DIC-related microvascular thrombosis. The rash does not blanch with pressure (unlike viral exanthems). Rapidly progressive purpura fulminans indicates severe DIC and predicts Waterhouse-Friderichsen syndrome.", s: "Assessment" },
  { q: "What is Waterhouse-Friderichsen syndrome?", o: ["Viral encephalitis causing seizures", "Bilateral adrenal hemorrhage from meningococcal sepsis causing acute adrenal insufficiency", "Chronic subdural hematoma in elderly patients", "Autoimmune encephalitis"], a: 1, r: "Waterhouse-Friderichsen syndrome is bilateral adrenal hemorrhagic necrosis caused by fulminant meningococcal (or other gram-negative) sepsis and DIC. It presents with purpura fulminans, hemodynamic collapse, and acute adrenal crisis. Treatment: emergent IV hydrocortisone, massive fluid resuscitation, vasopressors.", s: "Neurological" },
  { q: "Which CSF finding best differentiates viral from bacterial meningitis?", o: ["Opening pressure alone", "CSF glucose level — normal in viral, markedly low in bacterial meningitis", "CSF color", "Patient age"], a: 1, r: "CSF glucose is the most reliable differentiator: normal in viral meningitis (bacteria are not consuming glucose) and markedly low in bacterial meningitis (<40 mg/dL or CSF:serum glucose ratio <0.4). WBC differential also helps: neutrophilic in bacterial, lymphocytic in viral.", s: "Assessment" },
  { q: "The classic triad of bacterial meningitis (fever, neck stiffness, altered mental status) is present in what percentage of cases?", o: [">90%", "~75%", "~44%", "~20%"], a: 2, r: "The complete classic triad is present in only ~44% of bacterial meningitis cases. However, nearly all patients have at least 2 of 4 features: headache, fever, neck stiffness, or altered mental status. Clinicians should maintain high suspicion with any combination of these symptoms.", s: "Assessment" },
  { q: "Which organism is the most common cause of bacterial meningitis in adults?", o: ["Neisseria meningitidis", "Streptococcus pneumoniae", "Haemophilus influenzae", "Listeria monocytogenes"], a: 1, r: "S. pneumoniae is the most common cause of bacterial meningitis in adults (and overall in the post-Hib vaccine era). Gram stain shows gram-positive diplococci. Treatment: ceftriaxone ± vancomycin (for penicillin-resistant strains). Mortality remains 20-30% even with appropriate treatment.", s: "Neurological" },
  { q: "When should CT be obtained before lumbar puncture?", o: ["Always, in every patient with suspected meningitis", "Only when specific risk factors present: altered mental status, focal deficits, papilledema, seizures, or immunocompromised state", "Never, LP should always be done immediately", "Only in children under 2 years"], a: 1, r: "CT before LP is only indicated when herniation risk factors are present: altered mental status, focal neurological deficits, papilledema, new seizures, or immunocompromised state. In a young patient with classic meningismus and no red flags, LP can proceed without CT — but antibiotics must NEVER be delayed for imaging.", s: "Assessment" },
  { q: "The USPSTF recommends one-time screening abdominal ultrasound for AAA in which population?", o: ["All adults over age 50", "Men aged 65-75 who have ever smoked", "All women over age 65", "Men aged 50-65 with hypertension"], a: 1, r: "USPSTF Grade B recommendation: one-time screening abdominal ultrasound for men aged 65-75 who have EVER smoked (even if quit decades ago). No routine screening is recommended for women or men who have never smoked, though it may be considered with a positive family history.", s: "Assessment" },
  { q: "At what diameter is an abdominal aortic aneurysm defined?", o: ["≥2.0 cm", "≥2.5 cm", "≥3.0 cm", "≥4.0 cm"], a: 2, r: "An AAA is defined as focal dilation of the abdominal aorta to ≥3.0 cm or >50% increase over normal diameter. Normal infrarenal aortic diameter is 1.5-2.5 cm. Size determines management: <5.5 cm surveillance, ≥5.5 cm surgical repair consideration.", s: "Cardiovascular" },
  { q: "What is the strongest modifiable risk factor for AAA development and progression?", o: ["Hypertension", "Diabetes", "Smoking", "Hyperlipidemia"], a: 2, r: "Smoking is the strongest modifiable risk factor for AAA — 90% of AAA patients have a smoking history. Smoking accelerates aneurysm growth through matrix metalloproteinase activation and elastin degradation. Smoking cessation is the ONLY intervention proven to slow AAA growth rate.", s: "Cardiovascular" },
  { q: "At what AAA size threshold is elective surgical repair recommended for men?", o: ["≥4.0 cm", "≥4.5 cm", "≥5.0 cm", "≥5.5 cm"], a: 3, r: "Elective repair is recommended at ≥5.5 cm in men (≥5.0 cm in women, due to higher rupture risk at smaller diameters). The UK Small Aneurysm Trial and ADAM trial showed no survival benefit from repairing aneurysms <5.5 cm. Repair is also indicated for rapid expansion (>1 cm/year) or symptoms.", s: "Cardiovascular" }
];
